package com.cora.stylefinder.member.config;
import com.cora.stylefinder.member.member.*; import io.jsonwebtoken.Claims; import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.IOException; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.core.authority.SimpleGrantedAuthority; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter { private final JwtService jwt; private final UserRepository users; public JwtAuthenticationFilter(JwtService jwt,UserRepository users){this.jwt=jwt;this.users=users;} @Override protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{String h=req.getHeader("Authorization");if(h!=null&&h.startsWith("Bearer ")){try{Claims c=jwt.parse(h.substring(7));if("access".equals(c.get("type",String.class))){users.findById(Long.valueOf(c.getSubject())).ifPresent(u->{var a=new UsernamePasswordAuthenticationToken(u,null,java.util.List.of(new SimpleGrantedAuthority("ROLE_"+u.getRole().name())));SecurityContextHolder.getContext().setAuthentication(a);});}}catch(Exception ignored){}}chain.doFilter(req,res);}}
